const metrics = $('Get Journal Metrics').first().json;
const symbols = $('Get Per-Symbol Breakdown').all().map(i => i.json);

const today = new Date().toISOString().split('T')[0];

// Find top 3 winners and losers by avg P&L
const sorted = [...symbols].sort((a, b) => (b.avg_pnl || 0) - (a.avg_pnl || 0));
const winners = sorted.filter(s => (s.avg_pnl || 0) > 0).slice(0, 3);
const losers = sorted.filter(s => (s.avg_pnl || 0) < 0).slice(-3).reverse();

const brief = {
  date: today,
  generated_at: new Date().toISOString(),
  metrics: {
    win_rate: metrics.win_rate,
    expectancy: metrics.expectancy,
    profit_factor: metrics.profit_factor,
    avg_win: metrics.avg_win,
    avg_loss: metrics.avg_loss,
    total_pnl: metrics.total_pnl,
    current_streak: metrics.current_streak
  },
  top_winners: winners.map(s => ({ symbol: s.symbol, avg_pnl: s.avg_pnl, win_rate: s.win_rate, trades: s.trade_count })),
  top_losers: losers.map(s => ({ symbol: s.symbol, avg_pnl: s.avg_pnl, win_rate: s.win_rate, trades: s.trade_count })),
  q2_goal_status: {
    target_avg_loss_pct: '0.25-0.33%',
    current_avg_loss: metrics.avg_loss,
    current_win_rate: metrics.win_rate,
    target_win_rate: '40%'
  }
};

return [{ json: brief }];
